schema.sql:
-- Create extensions
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";

-- Create users table
CREATE TABLE IF NOT EXISTS users (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  email text UNIQUE NOT NULL,
  phone text,
  "firstName" text,
  "lastName" text,
  "totalPoints" integer DEFAULT 0,
  "currentTier" text,
  avatar text,
  "referralCode" text UNIQUE,
  created_at timestamptz DEFAULT now(),
  updated_at timestamptz DEFAULT now()
);

-- Create menu_items table
CREATE TABLE IF NOT EXISTS menu_items (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  name text NOT NULL,
  description text,
  price numeric NOT NULL,
  category text,
  image text,
  available boolean DEFAULT true,
  "preparationTime" integer,
  calories integer,
  created_at timestamptz DEFAULT now(),
  updated_at timestamptz DEFAULT now()
);

-- Create sizes table
CREATE TABLE IF NOT EXISTS sizes (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  name text NOT NULL,
  "priceModifier" numeric DEFAULT 0,
  created_at timestamptz DEFAULT now()
);

-- Create customizations table
CREATE TABLE IF NOT EXISTS customizations (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  name text NOT NULL,
  price numeric DEFAULT 0,
  category text,
  created_at timestamptz DEFAULT now()
);

-- Create orders table
CREATE TABLE IF NOT EXISTS orders (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  "userId" uuid NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  subtotal numeric DEFAULT 0,
  tax numeric DEFAULT 0,
  discount numeric DEFAULT 0,
  total numeric DEFAULT 0,
  "pointsEarned" integer DEFAULT 0,
  "pointsRedeemed" integer DEFAULT 0,
  "paymentMethod" text,
  status text DEFAULT 'pending',
  "estimatedReadyTime" timestamptz,
  "completedAt" timestamptz,
  "qrCode" text,
  created_at timestamptz DEFAULT now(),
  updated_at timestamptz DEFAULT now()
);

-- Create order_items table
CREATE TABLE IF NOT EXISTS order_items (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  "orderId" uuid NOT NULL REFERENCES orders(id) ON DELETE CASCADE,
  "menuItemId" uuid REFERENCES menu_items(id) ON DELETE SET NULL,
  name text NOT NULL,
  quantity integer NOT NULL DEFAULT 1,
  size text,
  customizations text[] DEFAULT ARRAY[]::text[],
  price numeric NOT NULL,
  image text,
  created_at timestamptz DEFAULT now()
);

-- Create rewards table
CREATE TABLE IF NOT EXISTS rewards (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  name text NOT NULL,
  description text,
  "pointsCost" integer NOT NULL,
  category text,
  image text,
  available boolean DEFAULT true,
  "expiryDays" integer,
  created_at timestamptz DEFAULT now()
);

-- Create transactions table
CREATE TABLE IF NOT EXISTS transactions (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  "userId" uuid NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  type text NOT NULL,
  points integer DEFAULT 0,
  amount numeric DEFAULT 0,
  description text,
  "orderId" uuid REFERENCES orders(id) ON DELETE SET NULL,
  created_at timestamptz DEFAULT now()
);

-- Create loyalty_cards table
CREATE TABLE IF NOT EXISTS loyalty_cards (
  "userId" uuid PRIMARY KEY REFERENCES users(id) ON DELETE CASCADE,
  "cardNumber" text UNIQUE NOT NULL,
  balance integer DEFAULT 0,
  tier text,
  "pointsToNextTier" integer DEFAULT 0,
  "lifetimePoints" integer DEFAULT 0,
  "memberSince" timestamptz DEFAULT now(),
  created_at timestamptz DEFAULT now(),
  updated_at timestamptz DEFAULT now()
);

-- Create payment_cards table
CREATE TABLE IF NOT EXISTS payment_cards (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  last4 text NOT NULL,
  brand text,
  "expiryMonth" integer,
  "expiryYear" integer,
  "isDefault" boolean DEFAULT false,
  created_at timestamptz DEFAULT now()
);

-- Create notifications table
CREATE TABLE IF NOT EXISTS notifications (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  title text NOT NULL,
  body text,
  type text,
  read boolean DEFAULT false,
  data jsonb,
  created_at timestamptz DEFAULT now()
);

-- Create indexes
CREATE INDEX IF NOT EXISTS idx_orders_userId ON orders("userId");
CREATE INDEX IF NOT EXISTS idx_orders_status ON orders(status);
CREATE INDEX IF NOT EXISTS idx_orders_created_at ON orders(created_at);
CREATE INDEX IF NOT EXISTS idx_order_items_orderId ON order_items("orderId");
CREATE INDEX IF NOT EXISTS idx_order_items_menuItemId ON order_items("menuItemId");
CREATE INDEX IF NOT EXISTS idx_transactions_userId ON transactions("userId");
CREATE INDEX IF NOT EXISTS idx_transactions_orderId ON transactions("orderId");
CREATE INDEX IF NOT EXISTS idx_transactions_created_at ON transactions(created_at);
CREATE INDEX IF NOT EXISTS idx_menu_items_category ON menu_items(category);
CREATE INDEX IF NOT EXISTS idx_menu_items_available ON menu_items(available);
CREATE INDEX IF NOT EXISTS idx_users_email ON users(email);
CREATE INDEX IF NOT EXISTS idx_users_referralCode ON users("referralCode");
CREATE INDEX IF NOT EXISTS idx_notifications_created_at ON notifications(created_at);
CREATE INDEX IF NOT EXISTS idx_notifications_read ON notifications(read);

-- Enable RLS
ALTER TABLE users ENABLE ROW LEVEL SECURITY;
ALTER TABLE menu_items ENABLE ROW LEVEL SECURITY;
ALTER TABLE sizes ENABLE ROW LEVEL SECURITY;
ALTER TABLE customizations ENABLE ROW LEVEL SECURITY;
ALTER TABLE orders ENABLE ROW LEVEL SECURITY;
ALTER TABLE order_items ENABLE ROW LEVEL SECURITY;
ALTER TABLE rewards ENABLE ROW LEVEL SECURITY;
ALTER TABLE transactions ENABLE ROW LEVEL SECURITY;
ALTER TABLE loyalty_cards ENABLE ROW LEVEL SECURITY;
ALTER TABLE payment_cards ENABLE ROW LEVEL SECURITY;
ALTER TABLE notifications ENABLE ROW LEVEL SECURITY;

-- RLS Policies for users
CREATE POLICY "Users can view own profile" ON users
  FOR SELECT USING (auth.uid() = id);
CREATE POLICY "Users can update own profile" ON users
  FOR UPDATE USING (auth.uid() = id);

-- RLS Policies for menu_items (public read)
CREATE POLICY "Menu items are publicly readable" ON menu_items
  FOR SELECT USING (true);

-- RLS Policies for sizes (public read)
CREATE POLICY "Sizes are publicly readable" ON sizes
  FOR SELECT USING (true);

-- RLS Policies for customizations (public read)
CREATE POLICY "Customizations are publicly readable" ON customizations
  FOR SELECT USING (true);

-- RLS Policies for orders
CREATE POLICY "Users can view own orders" ON orders
  FOR SELECT USING (auth.uid() = "userId");
CREATE POLICY "Users can insert own orders" ON orders
  FOR INSERT WITH CHECK (auth.uid() = "userId");
CREATE POLICY "Users can update own orders" ON orders
  FOR UPDATE USING (auth.uid() = "userId");

-- RLS Policies for order_items
CREATE POLICY "Users can view own order items" ON order_items
  FOR SELECT USING (EXISTS (
    SELECT 1 FROM orders WHERE orders.id = order_items."orderId" AND orders."userId" = auth.uid()
  ));
CREATE POLICY "Users can insert own order items" ON order_items
  FOR INSERT WITH CHECK (EXISTS (
    SELECT 1 FROM orders WHERE orders.id = order_items."orderId" AND orders."userId" = auth.uid()
  ));

-- RLS Policies for rewards (public read)
CREATE POLICY "Rewards are publicly readable" ON rewards
  FOR SELECT USING (true);

-- RLS Policies for transactions
CREATE POLICY "Users can view own transactions" ON transactions
  FOR SELECT USING (auth.uid() = "userId");
CREATE POLICY "Users can insert own transactions" ON transactions
  FOR INSERT WITH CHECK (auth.uid() = "userId");

-- RLS Policies for loyalty_cards
CREATE POLICY "Users can view own loyalty card" ON loyalty_cards
  FOR SELECT USING (auth.uid() = "userId");
CREATE POLICY "Users can update own loyalty card" ON loyalty_cards
  FOR UPDATE USING (auth.uid() = "userId");

-- RLS Policies for payment_cards
CREATE POLICY "Users can view own payment cards" ON payment_cards
  FOR SELECT USING (true);
CREATE POLICY "Users can insert own payment cards" ON payment_cards
  FOR INSERT WITH CHECK (true);
CREATE POLICY "Users can update own payment cards" ON payment_cards
  FOR UPDATE USING (true);
CREATE POLICY "Users can delete own payment cards" ON payment_cards
  FOR DELETE USING (true);

-- RLS Policies for notifications
CREATE POLICY "Users can view own notifications" ON notifications
  FOR SELECT USING (true);
CREATE POLICY "Users can update own notifications" ON notifications
  FOR UPDATE USING (true);

-- Trigger function to handle new user signup
CREATE OR REPLACE FUNCTION public.handle_new_user()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER SET search_path = public
AS $$
BEGIN
  INSERT INTO public.users (id, email, created_at, updated_at)
  VALUES (new.id, new.email, now(), now())
  ON CONFLICT (id) DO NOTHING;
  RETURN new;
END;
$$;

-- Trigger on auth.users
DROP TRIGGER IF EXISTS on_auth_user_created ON auth.users;
CREATE TRIGGER on_auth_user_created
  AFTER INSERT ON auth.users
  FOR EACH ROW EXECUTE FUNCTION public.handle_new_user();
